import{c as r,Z as l,Q as e,j as o,o as i,m as n}from"./chunks/framework.qjzPVSkb.js";const q=JSON.parse('{"title":"挑战：用 AI 搭建一个个人网站","description":"开放式挑战——不提供步骤，只给需求规格。用 AI 工具从零搭建并部署一个多页面的个人简历网站","frontmatter":{"title":"挑战：用 AI 搭建一个个人网站","description":"开放式挑战——不提供步骤，只给需求规格。用 AI 工具从零搭建并部署一个多页面的个人简历网站","difficulty":"advanced"},"headers":[],"relativePath":"practices/challenge-01.md","filePath":"practices/challenge-01.md"}'),d={name:"practices/challenge-01.md"};function s(h,t,u,c,g,p){const a=l("DifficultyBadge");return e(),o("div",null,[i(a,{level:"advanced"}),t[0]||(t[0]=n('<h1 id="挑战-用-ai-搭建一个个人网站" tabindex="-1">挑战：用 AI 搭建一个个人网站 <a class="header-anchor" href="#挑战-用-ai-搭建一个个人网站" aria-label="Permalink to &quot;挑战：用 AI 搭建一个个人网站&quot;">​</a></h1><blockquote><p>⚠️ 这是一个<strong>开放式挑战任务</strong>，不是教程。没有标准答案，不提供分步指导。你需要自己想办法完成。</p></blockquote><h2 id="挑战说明" tabindex="-1">挑战说明 <a class="header-anchor" href="#挑战说明" aria-label="Permalink to &quot;挑战说明&quot;">​</a></h2><p>本篇不是教程——它没有&quot;第 1 步、第 2 步&quot;。你拿到的是一份<strong>需求规格书</strong>，你的任务是用 AI 工具独立完成它。</p><p><strong>规则很简单：</strong></p><ul><li>你只能使用 AI 工具（ChatGPT、Claude、Cursor、Windsurf、Copilot 等）</li><li>没有标准答案——怎么实现、用什么技术栈，完全由你决定</li><li>最终交付物是一个<strong>已部署上线</strong>、可访问的个人简历网站</li><li>过程中遇到的任何问题，优先问 AI 而不是查文档</li></ul><p>这个挑战的设计思路是：在实际工作中，你不会拿到&quot;保姆级教程&quot;，你拿到的是需求。能不能拆解需求、向 AI 提出正确的问题、把 AI 产出的代码整合成完整项目——这些才是真正需要练习的能力。</p><hr><h2 id="需求规格" tabindex="-1">需求规格 <a class="header-anchor" href="#需求规格" aria-label="Permalink to &quot;需求规格&quot;">​</a></h2><p>你需要搭建一个<strong>个人简历网站</strong>，包含以下四个页面或区块：</p><h3 id="_1-首页" tabindex="-1">1. 首页 <a class="header-anchor" href="#_1-首页" aria-label="Permalink to &quot;1. 首页&quot;">​</a></h3><ul><li>个人简介段落（至少 50 字）</li><li>一个头像占位区域（用纯 CSS 实现，不需要真实照片）</li><li>一句<strong>个人标语</strong>（slogan），突出展示</li><li>页面整体有明确的视觉焦点，让访客一眼知道你是谁</li></ul><h3 id="_2-技能页" tabindex="-1">2. 技能页 <a class="header-anchor" href="#_2-技能页" aria-label="Permalink to &quot;2. 技能页&quot;">​</a></h3><ul><li>列出至少 6 项技能，分为前端、后端、设计等类别</li><li>每项技能有<strong>可视化标识</strong>——进度条、星级、标签皆可</li><li>类别之间在视觉上有清晰区分</li><li>整体布局在移动端不塌陷</li></ul><h3 id="_3-项目页" tabindex="-1">3. 项目页 <a class="header-anchor" href="#_3-项目页" aria-label="Permalink to &quot;3. 项目页&quot;">​</a></h3><ul><li>展示至少 <strong>3 个完整项目</strong></li><li>每个项目包含：项目名称、一句话描述、一个截图占位区域、技术栈标签</li><li>截图占位用纯 CSS 实现（灰色矩形 + 图标即可）</li><li>项目之间通过卡片形式区分，视觉层次分明</li></ul><h3 id="_4-联系方式" tabindex="-1">4. 联系方式 <a class="header-anchor" href="#_4-联系方式" aria-label="Permalink to &quot;4. 联系方式&quot;">​</a></h3><p>以下二选一：</p><ul><li><strong>表单方案</strong>：包含姓名、邮箱、留言三个字段，有提交反馈</li><li><strong>社交链接方案</strong>：至少 4 个平台链接（GitHub、邮箱、LinkedIn 等），带 hover 动效</li></ul><p>额外加分：两种都做。</p><h3 id="技术要求-硬性条件" tabindex="-1">技术要求（硬性条件） <a class="header-anchor" href="#技术要求-硬性条件" aria-label="Permalink to &quot;技术要求（硬性条件）&quot;">​</a></h3><ul><li><strong>纯前端实现</strong>：HTML + CSS + JavaScript，或使用 React/Vue 等框架（需能本地运行）</li><li><strong>响应式设计</strong>：手机（&lt; 768px）、平板（768px - 1024px）、桌面（&gt; 1024px）三种尺寸均正常显示</li><li><strong>部署上线</strong>：发布到 GitHub Pages 或 Vercel，确保可通过公开 URL 访问</li><li><strong>使用 AI 工具完成全部编码</strong>：不手动写核心逻辑，所有代码由 AI 生成、你负责整合与调试</li><li><strong>不含外部图片</strong>：所有视觉元素用 CSS 实现</li><li><strong>不引入后端服务</strong>：表单提交可以用 <code>mailto:</code> 或静默处理</li></ul><hr><h2 id="可用工具" tabindex="-1">可用工具 <a class="header-anchor" href="#可用工具" aria-label="Permalink to &quot;可用工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>工具</th><th>用途</th></tr></thead><tbody><tr><td>AI 编程 IDE</td><td>Cursor / Windsurf / Copilot</td><td>在编辑器中直接生成和修改代码</td></tr><tr><td>AI 对话</td><td>ChatGPT / Claude</td><td>生成代码片段、设计方案、Debug</td></tr><tr><td>部署平台</td><td>GitHub Pages / Vercel</td><td>免费部署静态网站</td></tr></tbody></table><p>建议组合：用 ChatGPT 或 Claude 先讨论整体设计和技术方案，然后用 Cursor 或 Windsurf 在编辑器中逐步实现。</p><hr><h2 id="评估标准" tabindex="-1">评估标准 <a class="header-anchor" href="#评估标准" aria-label="Permalink to &quot;评估标准&quot;">​</a></h2><p>完成挑战后，从以下四个维度自评：</p><table tabindex="0"><thead><tr><th>维度</th><th>说明</th></tr></thead><tbody><tr><td><strong>功能完整性</strong></td><td>四个页面/区块全部实现，交互逻辑正常，没有明显 bug</td></tr><tr><td><strong>代码质量</strong></td><td>HTML 语义化、CSS 无大量冗余、JS 逻辑清晰、有适当注释</td></tr><tr><td><strong>视觉设计</strong></td><td>色彩搭配协调、排版整洁、四个页面风格统一、响应式断点合理</td></tr><tr><td><strong>AI 利用效率</strong></td><td>向 AI 提问的质量如何？是否需要反复修正才能得到可用的代码？</td></tr></tbody></table><p>达到所有标准即为&quot;挑战通过&quot;。不必追求完美——追求&quot;能用 + 好看&quot;即可。</p><hr><h2 id="提示-非步骤" tabindex="-1">提示（非步骤） <a class="header-anchor" href="#提示-非步骤" aria-label="Permalink to &quot;提示（非步骤）&quot;">​</a></h2><p>以下不是操作步骤，而是策略建议——你可以采纳，也可以用自己的方式：</p><ul><li><strong>先设计方案，再写代码</strong>：用 AI 生成一份完整的页面设计方案（布局草图、配色、字体选择），确认可行后再动手</li><li><strong>分模块推进</strong>：按页面逐个完成，每完成一个模块就让 AI Review 一次，趁早发现问题</li><li><strong>先让 AI 试错</strong>：遇到报错或效果不对，把现象和代码一起扔给 AI，让它先给出诊断——大多数问题 AI 都能自己解决</li><li><strong>第一次生成的代码几乎都不完美</strong>：把 AI 当结对编程伙伴，持续对话、迭代优化，三到五轮对话后的代码质量会明显提升</li></ul><hr><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/practices/cursor-website.html">用 Cursor 搭建网页</a> —— 了解 Cursor 的基本用法（但挑战中不要照抄步骤）</li><li><a href="/ai-knowledge/practices/chatgpt-coding.html">用 ChatGPT 辅助编程</a> —— 学会高效向 AI 提问和 Debug</li><li><a href="/ai-knowledge/tools/model-comparison.html">大模型对比：选哪个 AI 帮你编程</a> —— 不同 AI 在编程任务上的优劣势</li></ul>',38))])}const f=r(d,[["render",s]]);export{q as __pageData,f as default};
